import React, { useState } from "react";
import { PRIORITY_META, STATUS_META, STATUSES, formatDate } from "../utils/costants";

export default function FeatureCard({ feature, onEdit, onDelete, onStatusChange }) {
  const [confirmDelete, setConfirmDelete] = useState(false);

  const pm = PRIORITY_META[feature.priority];
  const sm = STATUS_META[feature.status];

  function handleDeleteClick() {
    if (confirmDelete) {
      onDelete(feature.id);
    } else {
      setConfirmDelete(true);
    }
  }

  function handleBlur() {
    setConfirmDelete(false);
  }

  function cycleStatus() {
    const idx = STATUSES.indexOf(feature.status);
    const next = STATUSES[(idx + 1) % STATUSES.length];
    onStatusChange(feature.id, next);
  }

  return (
    <article className={`card status-${feature.status.replace(" ", "-").toLowerCase()}`}>
      <div className="card-top">
        <span className="priority-badge" style={{ "--badge-color": pm.color }}>
          {feature.priority}
        </span>
        <span className="card-date">{formatDate(feature.createdAt)}</span>
      </div>

      <h3 className="card-title">{feature.title}</h3>
      <p className="card-desc">{feature.description}</p>

      <div className="card-footer">
        <button
          className={`status-btn status-${feature.status.replace(" ", "-").toLowerCase()}`}
          onClick={cycleStatus}
          title="Click to advance status"
        >
          <span className="status-icon">{sm.icon}</span>
          {sm.label}
        </button>

        <div className="card-actions">
          <button className="btn-icon btn-edit" onClick={() => onEdit(feature)} aria-label="Edit">
            70e
          </button>
          <button
            className={`btn-icon btn-delete ${confirmDelete ? "confirm" : ""}`}
            onClick={handleDeleteClick}
            onBlur={handleBlur}
            aria-label={confirmDelete ? "Confirm delete" : "Delete"}
            title={confirmDelete ? "Click again to confirm" : "Delete"}
          >
            5D1
          </button>
        </div>
      </div>
    </article>
  );
}
